CSS = """
<style>
:root{--bg:#080d18;--panel:rgba(18,27,44,.78);--line:rgba(164,183,219,.16);--text:#edf4ff;--muted:#9aa8c1;--gold:#d8b86c;--cyan:#63d7ff;}
html,body,[data-testid="stAppViewContainer"]{background:radial-gradient(circle at top left,rgba(74,113,255,.16),transparent 32%),radial-gradient(circle at top right,rgba(216,184,108,.10),transparent 24%),linear-gradient(180deg,#080d18 0%,#0b1020 50%,#070a12 100%);color:var(--text)}
[data-testid="stHeader"]{background:rgba(8,13,24,0)}[data-testid="stToolbar"]{display:none}.block-container{padding-top:2rem;padding-bottom:4rem;max-width:1480px}
.hero-clean{border:1px solid var(--line);background:linear-gradient(135deg,rgba(18,27,44,.72),rgba(9,15,28,.50));border-radius:30px;padding:30px 34px;box-shadow:0 24px 70px rgba(0,0,0,.28);text-align:center;position:relative;overflow:hidden}.hero-clean:after{content:"";position:absolute;right:-120px;top:-140px;width:330px;height:330px;background:radial-gradient(circle,rgba(99,215,255,.13),transparent 64%);pointer-events:none}.hero-clean h1{font-size:3.25rem;line-height:1;margin:0;letter-spacing:-.055em;color:#fff;font-weight:850}.eyebrow{color:var(--gold);letter-spacing:.18em;text-transform:uppercase;font-size:.78rem;font-weight:800}
.run-button-row{display:flex;justify-content:center;margin:22px 0 8px 0}.run-button-row>div{width:min(360px,100%)}
.metric-card{border:1px solid var(--line);background:linear-gradient(180deg,rgba(20,31,51,.82),rgba(12,19,33,.72));border-radius:22px;padding:20px;min-height:112px;box-shadow:0 16px 44px rgba(0,0,0,.23)}.metric-label{color:var(--muted);text-transform:uppercase;letter-spacing:.12em;font-size:.72rem;font-weight:800}.metric-value{color:#fff;font-size:2.2rem;font-weight:800;letter-spacing:-.04em;margin-top:8px}.metric-note{color:#aab6cc;font-size:.87rem;margin-top:7px;line-height:1.35}.section-title{margin-top:34px;margin-bottom:16px;font-size:1.28rem;font-weight:850;letter-spacing:-.025em;color:#fff}.section-subtitle{display:none}.lane-card{border:1px solid var(--line);background:rgba(14,22,36,.62);border-radius:18px;padding:16px;min-height:100px}.lane-title{color:#fff;font-weight:850;font-size:1rem}.lane-metrics{display:flex;gap:8px;flex-wrap:wrap;margin-top:14px}.lane-metrics span{border:1px solid rgba(216,184,108,.18);background:rgba(216,184,108,.055);color:#f2deaa;border-radius:999px;padding:5px 9px;font-size:.76rem}.signal{border-left:3px solid rgba(99,215,255,.85);background:rgba(99,215,255,.055);border-radius:14px;padding:12px 14px;margin-bottom:10px;color:#dceaff}.signal strong{color:#fff}.caption{display:none}
div[data-testid="stButton"]{display:flex;justify-content:center}div[data-testid="stButton"] button{width:100%;max-width:360px;border-radius:16px;min-height:52px;border:1px solid rgba(216,184,108,.35);background:linear-gradient(135deg,rgba(216,184,108,.95),rgba(117,227,180,.7));color:#0a1020;font-weight:900;box-shadow:0 16px 34px rgba(0,0,0,.24)}.stPlotlyChart{border-radius:22px;overflow:hidden;border:1px solid rgba(164,183,219,.10);background:rgba(7,12,22,.18)}
/* Dark select/dropdown cleanup */
div[data-baseweb="select"]>div{background:rgba(12,19,33,.92)!important;border-color:rgba(164,183,219,.22)!important;color:#edf4ff!important;border-radius:14px!important}div[data-baseweb="select"] span{color:#edf4ff!important}div[data-baseweb="popover"]{background:#0d1526!important}ul[role="listbox"],div[role="listbox"]{background:#0d1526!important;color:#edf4ff!important;border:1px solid rgba(164,183,219,.22)!important}li[role="option"],div[role="option"]{background:#0d1526!important;color:#edf4ff!important}
/* Native dataframe fallback styling */
div[data-testid="stDataFrame"]{border:1px solid var(--line);border-radius:18px;overflow:hidden;background:rgba(10,16,28,.72)!important}div[data-testid="stDataFrame"] *{color:#edf4ff!important}
.dark-table-wrap{overflow:auto;border:1px solid var(--line);border-radius:18px;background:rgba(10,16,28,.78);box-shadow:0 16px 42px rgba(0,0,0,.18);margin-bottom:14px}.dark-data-table{border-collapse:separate;border-spacing:0;width:100%;font-size:.82rem;color:#edf4ff}.dark-data-table thead th{position:sticky;top:0;background:#111b2e;color:#fff;text-align:left;padding:10px 12px;border-bottom:1px solid rgba(164,183,219,.22);white-space:nowrap;z-index:2}.dark-data-table tbody td{padding:9px 12px;border-bottom:1px solid rgba(164,183,219,.10);color:#dce7f7;vertical-align:top;max-width:360px}.dark-data-table tbody tr:nth-child(even){background:rgba(255,255,255,.025)}.dark-data-table tbody tr:hover{background:rgba(99,215,255,.06)}
/* Expander cleanup */
div[data-testid="stExpander"]{border:1px solid rgba(164,183,219,.16);border-radius:16px;background:rgba(10,16,28,.42)}
</style>
"""
